Yes — best fit is a small **pi extension**.

Why extension, not just a skill/template:
- **prompt template / skill** can standardize the review prompt
- **extension** can actually run `gh`/`git`, fetch the PR ref, and then hand a structured review task to the model

Assuming **GitHub + `gh` CLI**, put this in:

- global: `~/.pi/agent/extensions/pr-review.ts`
- or project-local: `.pi/extensions/pr-review.ts`

Then run `/reload`.

```ts
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

type PrView = {
	number: number;
	title: string;
	url: string;
	baseRefName: string;
	headRefName: string;
};

function formatExecError(command: string, args: string[], stdout: string, stderr: string): string {
	return [`$ ${command} ${args.join(" ")}`, stdout.trim(), stderr.trim()].filter(Boolean).join("\n");
}

async function execChecked(pi: ExtensionAPI, command: string, args: string[]): Promise<string> {
	const result = await pi.exec(command, args);
	if (result.code !== 0) {
		throw new Error(formatExecError(command, args, result.stdout, result.stderr));
	}
	return result.stdout.trim();
}

async function tryFetchPrRef(pi: ExtensionAPI, prNumber: number): Promise<{ localRef?: string; note: string }> {
	const remotesRaw = await execChecked(pi, "git", ["remote"]);
	const remotes = remotesRaw.split(/\s+/).filter(Boolean);

	if (remotes.length === 0) {
		return { note: "No git remotes found, so local PR fetch was skipped." };
	}

	const orderedRemotes = [...new Set(["origin", "upstream", ...remotes])].filter((r) => remotes.includes(r));
	const localRef = `refs/pi/review/pr-${prNumber}`;
	const errors: string[] = [];

	for (const remote of orderedRemotes) {
		const result = await pi.exec("git", ["fetch", remote, `pull/${prNumber}/head:${localRef}`]);
		if (result.code === 0) {
			return {
				localRef,
				note: `Fetched ${localRef} from remote '${remote}'.`,
			};
		}

		const output = (result.stderr || result.stdout).trim() || "fetch failed";
		errors.push(`${remote}: ${output}`);
	}

	return {
		note: `Could not fetch pull/${prNumber}/head from any remote.\n${errors.join("\n")}`,
	};
}

function buildReviewPrompt(params: {
	repoSlug: string;
	pr: PrView;
	lastSha: string;
	lastHeadline: string;
	focus: string;
	localRef?: string;
	fetchNote: string;
}): string {
	const { repoSlug, pr, lastSha, lastHeadline, focus, localRef, fetchNote } = params;

	const focusText = focus.trim()
		? `Pay extra attention to these pain-points:\n- ${focus.trim()}`
		: "No extra pain-points were specified by the user.";

	const inspectText = localRef
		? [
				`Local PR ref is available: ${localRef}`,
				`Use local git inspection for the last commit only:`,
				`- git show --stat --summary ${lastSha}`,
				`- git diff ${lastSha}^ ${lastSha}`,
				`- inspect changed files with read/grep/find/ls as needed`,
		  ].join("\n")
		: [
				`Local fetch failed, so use gh as fallback.`,
				`Useful commands:`,
				`- gh api repos/${repoSlug}/commits/${lastSha}`,
				`- gh pr view ${pr.number} --json commits`,
		  ].join("\n");

	return [
		`Review GitHub PR #${pr.number}, but review ONLY its last commit.`,
		``,
		`Target:`,
		`- repo: ${repoSlug}`,
		`- PR: #${pr.number} ${pr.title}`,
		`- URL: ${pr.url}`,
		`- base branch: ${pr.baseRefName}`,
		`- head branch: ${pr.headRefName}`,
		`- last commit SHA: ${lastSha}`,
		`- last commit subject: ${lastHeadline || "(unknown)"}`,
		``,
		`${focusText}`,
		``,
		`Fetch status:`,
		`${fetchNote}`,
		``,
		`Instructions:`,
		`1. Review only the last commit, not the full PR history.`,
		`2. Do not modify files or git state.`,
		`3. Focus on correctness, regressions, missing tests, edge cases, and the requested pain-points.`,
		`4. Prefer concrete findings with file/symbol references.`,
		`5. If no issues are found, say so explicitly and summarize what you checked.`,
		``,
		`${inspectText}`,
		``,
		`Output format:`,
		`- Findings ordered by severity`,
		`- For each finding: severity, location, explanation, suggested fix`,
		`- If nothing is wrong: "No issues found"`,
	].join("\n");
}

export default function prReviewExtension(pi: ExtensionAPI) {
	let previousTools: string[] | undefined;

	pi.on("agent_end", async () => {
		if (previousTools) {
			pi.setActiveTools(previousTools);
			previousTools = undefined;
		}
	});

	pi.registerCommand("pr-review", {
		description: "Fetch a GitHub PR and review only its last commit",
		handler: async (args, ctx) => {
			if (!ctx.isIdle()) {
				ctx.ui.notify("Wait for the current task to finish, then run /pr-review again.", "warning");
				return;
			}

			const match = args.trim().match(/^(\d+)(?:\s+(.*))?$/s);
			let prNumberText = match?.[1] ?? "";
			let focus = match?.[2]?.trim() ?? "";

			if (!prNumberText) {
				prNumberText = (await ctx.ui.input("PR number", "123"))?.trim() ?? "";
			}
			if (!prNumberText) return;

			if (!focus) {
				focus = (await ctx.ui.input(
					"Pain-points to check (optional)",
					"e.g. nullability, concurrency, missing tests",
				))?.trim() ?? "";
			}

			try {
				await execChecked(pi, "git", ["rev-parse", "--is-inside-work-tree"]);

				const repoSlug = await execChecked(pi, "gh", [
					"repo",
					"view",
					"--json",
					"nameWithOwner",
					"--jq",
					".nameWithOwner",
				]);

				const pr = JSON.parse(
					await execChecked(pi, "gh", [
						"pr",
						"view",
						prNumberText,
						"--json",
						"number,title,url,baseRefName,headRefName",
					]),
				) as PrView;

				const lastSha = await execChecked(pi, "gh", [
					"pr",
					"view",
					prNumberText,
					"--json",
					"commits",
					"--jq",
					".commits[-1].oid",
				]);

				if (!lastSha) {
					throw new Error("Could not determine the last commit SHA for this PR.");
				}

				const lastHeadline = await execChecked(pi, "gh", [
					"pr",
					"view",
					prNumberText,
					"--json",
					"commits",
					"--jq",
					'.commits[-1].messageHeadline // ""',
				]);

				const fetchResult = await tryFetchPrRef(pi, pr.number);

				const availableTools = new Set(pi.getAllTools().map((tool) => tool.name));
				const reviewTools = ["read", "bash", "grep", "find", "ls"].filter((name) => availableTools.has(name));

				previousTools = pi.getActiveTools();
				if (reviewTools.length > 0) {
					pi.setActiveTools(reviewTools);
				}

				pi.setSessionName(`PR ${pr.number} last-commit review`);
				pi.sendUserMessage(
					buildReviewPrompt({
						repoSlug,
						pr,
						lastSha,
						lastHeadline,
						focus,
						localRef: fetchResult.localRef,
						fetchNote: fetchResult.note,
					}),
				);

				ctx.ui.notify(`Started last-commit review for PR #${pr.number}`, "info");
			} catch (error) {
				if (previousTools) {
					pi.setActiveTools(previousTools);
					previousTools = undefined;
				}
				ctx.ui.notify(error instanceof Error ? error.message : String(error), "error");
			}
		},
	});
}
```

### Usage

Inside pi:

```text
/pr-review 123 error handling, nullability, missing tests
```

Or just:

```text
/pr-review
```

and it’ll prompt you.

### What it does

- resolves current GitHub repo via `gh`
- fetches PR metadata by number
- finds the **last commit**
- tries to fetch `pull/<PR>/head` into a local ref
- temporarily switches tools to review-oriented ones:
  - `read`
  - `bash`
  - `grep`
  - `find`
  - `ls`
- sends a structured review prompt to the model
- restores your previous tool set after the review finishes

### Requirements

- `gh` installed and authenticated
- running inside a git checkout of the GitHub repo

