## Extension

```ts
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

const FETCH_REF_PATTERNS = [
	// GitHub / Gitea / Forgejo style
	"refs/pull/{n}/head",
	"refs/pulls/{n}/head",

	// GitLab-style MR refs
	"refs/merge-requests/{n}/head",
	"refs/merge_requests/{n}/head",
];

function fillPattern(pattern: string, prNumber: number): string {
	return pattern.replace(/\{n\}/g, String(prNumber));
}

function formatExecError(command: string, args: string[], stdout: string, stderr: string): string {
	return [`$ ${command} ${args.join(" ")}`, stdout.trim(), stderr.trim()].filter(Boolean).join("\n");
}

async function execChecked(pi: ExtensionAPI, command: string, args: string[]): Promise<string> {
	const result = await pi.exec(command, args);
	if (result.code !== 0) {
		throw new Error(formatExecError(command, args, result.stdout, result.stderr));
	}
	return result.stdout.trim();
}

async function chooseRemote(pi: ExtensionAPI, ctx: any): Promise<string> {
	const raw = await execChecked(pi, "git", ["remote"]);
	const remotes = raw.split(/\s+/).filter(Boolean);

	if (remotes.length === 0) {
		throw new Error("No git remotes found.");
	}

	if (remotes.includes("origin")) {
		return "origin";
	}

	if (remotes.length === 1) {
		return remotes[0];
	}

	const selected = await ctx.ui.select("Select remote for PR/MR fetch", remotes);
	if (!selected) {
		throw new Error("Remote selection was cancelled.");
	}
	return selected;
}

async function fetchReviewRef(pi: ExtensionAPI, remote: string, prNumber: number): Promise<{
	sourceRef: string;
	localRef: string;
}> {
	const localRef = `refs/pi/review/${prNumber}`;
	const failures: string[] = [];

	for (const pattern of FETCH_REF_PATTERNS) {
		const sourceRef = fillPattern(pattern, prNumber);
		const result = await pi.exec("git", ["fetch", remote, `${sourceRef}:${localRef}`]);

		if (result.code === 0) {
			return { sourceRef, localRef };
		}

		const msg = (result.stderr || result.stdout).trim() || "fetch failed";
		failures.push(`${sourceRef}: ${msg}`);
	}

	throw new Error(
		[
			`Could not fetch PR/MR #${prNumber} from remote '${remote}'.`,
			`Tried these ref patterns:`,
			...failures.map((x) => `- ${x}`),
			"",
			"If GitCode uses a different ref namespace, add it to FETCH_REF_PATTERNS.",
		].join("\n"),
	);
}

