void AssignAnalyzer::Analyze(const ir::AstNode *node)
{
    const auto program = checker_->VarBinder()->Program();
    globalClass_ = program->GlobalClass();

    AnalyzeClassDef(globalClass_);

    firstNonGlobalAdr_ = nextAdr_;
    AnalyzeNodes(node);
}

