        return false;
    }

    return exprStmt->Start().Program() == declNode->Start().Program() &&
           exprStmt->Start().index == declNode->Start().index &&
           exprStmt->End().Program() == declNode->End().Program() && exprStmt->End().index == declNode->End().index;
}

